module gpio_controller (  
    input wire clk,  
    input wire reset,  
    input wire [4:0] gpio_input,  
    output reg [4:0] gpio_output  
);  
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin  
        if (reset)  
            gpio_output <= 5'b00000;  
        else  
            gpio_output <= gpio_input;  
    end  
endmodule
